insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:1-6-business-growth:misc:6475d6b5', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students write ''this will lead to more profit'' as their analysis mark.</p><p><strong>✅ The correct idea:</strong> Examiners will not award analysis marks for just saying ''more profit''. You must explain the chain: WHY does the action lead to more profit? e.g., ''Reducing competition means fewer alternatives for customers, allowing the business to charge higher prices, increasing its profit margin (AN).''</p>", "question": "Why would an exam answer that simply states ''this will lead to more profit'' fail to earn an analysis mark?", "options": ["Because analysis marks are only for evaluation questions", "Because it skips the chain of reasoning explaining why", "Because ''profit'' is spelled incorrectly in most answers", "Because profit is not a valid business impact"]}'::jsonb, '{"answer": 1, "explain": "Examiners require the full chain of reasoning (e.g. reduced competition allows higher prices, increasing profit margin) rather than a bare assertion of ''more profit''."}'::jsonb),
('business:1-6-business-growth:misc:d759b2a5', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think increasing market share always means a business''s sales have increased.</p><p><strong>✅ The correct idea:</strong> Market share can increase even if the business''s sales stay the same — if the total market shrank. Sales can also rise while market share falls if the total market grew faster. Market share is ALWAYS relative to total market size.</p>", "question": "Can a business''s sales rise while its market share falls at the same time?", "options": ["No, market share and sales always move in the same direction", "Yes, but only if the business changes its prices", "No, market share can only be calculated using profit figures", "Yes, if the total market grows faster than its own sales"]}'::jsonb, '{"answer": 3, "explain": "Market share is always relative to total market size, so sales can rise while market share falls if the overall market is growing even faster."}'::jsonb),
('business:1-6-business-growth:misc:589f52da', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think organic growth and internal growth are different terms.</p><p><strong>✅ The correct idea:</strong> Organic growth and internal growth are the same thing — both refer to growing the business from within, without joining with another business. These terms are completely interchangeable in the exam.</p>", "question": "Are ''organic growth'' and ''internal growth'' different concepts in the exam?", "options": ["No, they are interchangeable terms for growing from within", "Yes, internal growth only applies to increasing output", "No, but only ''internal growth'' should be used in exam answers", "Yes, organic growth only applies to product development"]}'::jsonb, '{"answer": 0, "explain": "Organic growth and internal growth are the same thing and are fully interchangeable terms in the exam."}'::jsonb),
('business:1-6-business-growth:misc:215e5c9b', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For evaluation questions, students list pros and cons but never commit to a final decision.</p><p><strong>✅ The correct idea:</strong> An evaluation MUST end with a clear, justified decision — ''I recommend X because...''. Sitting on the fence scores zero evaluation marks no matter how good the analysis is. The examiner needs to see a decision AND a contextual justification.</p>", "question": "What is required for an evaluation answer to score full evaluation marks?", "options": ["A clear, justified final decision, not just a list of pros and cons", "Avoiding any mention of the case study business by name", "A list of pros and cons without picking a side, to stay balanced", "A minimum of six advantages and disadvantages"]}'::jsonb, '{"answer": 0, "explain": "Sitting on the fence scores zero evaluation marks — a clear decision with contextual justification is required, no matter how strong the analysis is."}'::jsonb),
('business:1-6-business-growth:tips:d6073d32', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Specific Term. Full Stop. Move On.", "reading": "<p>A 1-mark <strong>''Identify''</strong> question needs exactly one correct, specific answer. Do not waste time writing a sentence or definition.</p>\n    <p><strong>The Formula: One precise term = 1 mark ✅</strong></p>\n    <ul>\n      <li><strong>✅ Good Answer:</strong> <em>\"Merger\"</em> or <em>\"Horizontal takeover\"</em></li>\n      <li><strong>❌ Bad Answer:</strong> <em>\"The business grew by joining with another company.\"</em> — Too vague. Name the specific term.</li>\n    </ul>\n    <p><strong>⚠️ Examiner Warning (Q2i — Nina''s Knitting Supplies):</strong></p>\n    <p>The examiner noted this question \"dichotomised candidates\" — students either knew the terms for external growth and scored full marks, or didn''t and scored zero. This is a pure <strong>vocabulary test</strong>. Revise these terms: merger, takeover, horizontal, backward/forward vertical, diversification.</p>\n    <p><strong>🚫 Don''t confuse organic and external growth methods.</strong> ''Developing new products'' is organic. ''Merger'' is external. The question will always specify which type it wants.</p>", "question": "What is the correct approach to answering a 1-mark ''Identify'' question?", "options": ["Write a full sentence defining the term", "List as many relevant terms as possible", "Explain the advantages and disadvantages of the term", "Give one precise, specific term without explanation"]}'::jsonb, '{"answer": 3, "explain": "The formula for a 1-mark Identify question is one precise term = 1 mark — writing a vague sentence instead of naming the specific term (e.g. ''merger'') loses the mark."}'::jsonb),
('business:1-6-business-growth:tips:c67b48e9', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — State It + Apply It to the Business", "reading": "<p>A 2-mark <strong>''Explain''</strong> question needs a point AND a development linked to the specific business in the case study.</p>\n    <p><strong>The Formula: State the method (1 mark) + Apply to the business context (1 mark)</strong></p>\n    <ul>\n      <li><strong>Step 1 — State:</strong> Name the specific method of organic/external growth.</li>\n      <li><strong>Step 2 — Apply:</strong> Link it directly to the business using a detail from the case study.</li>\n    </ul>\n    <p><strong>✅ Good Answer — Boohoo (2 marks):</strong></p>\n    <p><em>\"Boohoo may have expanded organically by gaining new customers (1) through using social media platforms such as Instagram and Facebook to target its 16–24 year old fashion-conscious market (1).\"</em></p>\n    <p><strong>❌ Bad Answer (0–1 marks):</strong></p>\n    <p><em>\"Boohoo grew by selling more things.\"</em> — Too vague, no context, scores 0 or 1 at most.</p>\n    <p><strong>🚫 Don''t just define organic growth.</strong> The question asks HOW the specific business used it. Use a case study detail to prove you understand the application.</p>", "question": "What must a 2-mark ''Explain'' answer include to score both marks?", "options": ["A comparison between two different businesses", "A stated method plus its application to the business", "A definition of organic growth only", "Two different named methods with no further detail"]}'::jsonb, '{"answer": 1, "explain": "The formula for 2-mark Explain questions is: state the method (1 mark) plus apply it to the business context using a case study detail (1 mark)."}'::jsonb),
('business:1-6-business-growth:tips:66733aaa', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "<p>The 3-mark analyse question requires a precise three-step chain. <strong>You will score zero for analysis if you don''t apply it to the specific business in the case study.</strong></p>\n    <p><strong>The 3-Step Formula:</strong></p>\n    <ul>\n      <li><strong>Step 1 — Understanding (U):</strong> State the benefit or drawback clearly. e.g., \"Merging with a flour producer could reduce raw material costs.\"</li>\n      <li><strong>Step 2 — Application (APP):</strong> Quote or reference a specific detail from the case study. e.g., \"...as flour is a key ingredient in Greggs&apos pastries and sausage rolls.\"</li>\n      <li><strong>Step 3 — Analysis (AN):</strong> State the bottom-line business impact. e.g., \"This would allow Greggs to lower retail prices, increasing sales.\"</li>\n    </ul>\n    <p><strong>The \"So What?\" Rule:</strong> Keep asking \"So what?\" until you reach a real business impact on costs, revenue, profit, market share, or cash flow.</p>\n    <p><strong>✅ Full-mark Answer (Greggs, 3 marks):</strong><br/>\n    <em>\"Merging with a flour producer could reduce raw material costs (U), as flour is a key ingredient in Greggs&apos pastries and vegan sausage rolls (APP). This would allow Greggs to lower its retail prices, increasing sales and helping it achieve its aim of being the nation''s favourite food-on-the-go provider (AN).\"</em></p>\n    <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n    <em>\"It would reduce costs and increase profit.\"</em> — No application, no chain = 1 mark at best.</p>", "question": "According to the ''Holy Trinity'' formula for a 3-mark Analyse question, what three steps must the answer contain?", "options": ["Definition, Example, Conclusion", "Understanding, Application, Analysis", "Knowledge, Understanding, Evaluation", "Advantage, Disadvantage, Decision"]}'::jsonb, '{"answer": 1, "explain": "The three-step chain is Understanding (state the benefit/drawback), Application (a case study detail), and Analysis (the bottom-line business impact) — missing the application step scores zero for analysis."}'::jsonb),
('business:1-6-business-growth:tips:81bf466a', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Analyse Two — 6 marks — Do the 3-Mark Formula Twice", "reading": "<p>A 6-mark ''Analyse two...'' question is a 3-mark question done <strong>twice</strong>. Write two clearly separate, labelled paragraphs.</p>\n    <p><strong>Structure:</strong></p>\n    <ul>\n      <li><strong>Benefit 1:</strong> U → APP → AN (3 marks)</li>\n      <li><strong>Benefit 2:</strong> U → APP → AN (3 marks)</li>\n    </ul>\n    <p><strong>⚠️ Examiner Warning (Beautiful Buds Q8a):</strong></p>\n    <p>The examiner noted that many students jumped straight to \"more profit\" with no link to external growth. This scores zero. You must build the chain: <em>\"Merging (U) gives Beautiful Buds access to Green Gardens'' 12% market share (APP), increasing its sales revenue from selling plants through their retail outlets (AN).\"</em></p>\n    <p><strong>🚫 Do NOT write a conclusion.</strong> There are zero evaluation marks available in a 6-mark question. A conclusion wastes time.</p>\n    <p><strong>Context tip (Beautiful Buds):</strong> Contextual references include plants, garden centres, 12% market share, country''s largest retailer. Use them! ''Managers'' or ''Leaders'' alone are too vague for application marks.</p>", "question": "Why should a student NOT write a conclusion in a 6-mark ''Analyse two...'' question?", "options": ["Because conclusions are only allowed in 1-mark questions", "Because a conclusion would repeat the case study title", "Because the question only allows one paragraph in total", "Because zero evaluation marks are available, wasting time"]}'::jsonb, '{"answer": 3, "explain": "The card explicitly warns not to write a conclusion because a 6-mark Analyse question carries zero evaluation marks, making a conclusion a waste of exam time."}'::jsonb),
('business:1-6-business-growth:tips:64fb50ea', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 7 marks — Four-Paragraph Structure for Full Marks", "reading": "<p>A 7-mark evaluate question tests all four skills. Use this four-paragraph structure:</p>\n    <ul>\n      <li><strong>Paragraph 1 — K & U:</strong> State and briefly define an advantage of the strategy.</li>\n      <li><strong>Paragraph 2 — AN & APP:</strong> Build a contextual chain: U → APP (case study detail) → AN (business impact).</li>\n      <li><strong>Paragraph 3 — AN & APP:</strong> Repeat for a disadvantage or the alternative method.</li>\n      <li><strong>Paragraph 4 — Evaluation (3 points):</strong> Decision + Contextual justification + Impact/reasoning.</li>\n    </ul>\n    <p><strong>Evaluation sentence starters:</strong></p>\n    <ul>\n      <li><em>\"Overall, I believe [business] should [action] because...\"</em> — Decision (1 mark)</li>\n      <li><em>\"This is particularly important because the case study states that...\"</em> — Context (+1 mark)</li>\n      <li><em>\"Therefore, this approach would [specific business impact], meaning...\"</em> — Reasoning (+1 mark)</li>\n    </ul>\n    <p><strong>⚠️ \"Sitting on the fence\" = 0 evaluation marks.</strong> You MUST make a clear decision. The \"It depends on...\" construction is only valid if you then commit to which side that condition favours.</p>\n    <p><strong>Exemplar from Nina''s Knitting Supplies (full marks):</strong><br/>\n    <em>\"I think Nina should switch to external growth. A merger with a competitor knitting retailer (CONT) would help her grow market share faster than organic growth, which she has done for 15 years already (EVAL). This is especially important now that new competitors are entering the market, meaning organic growth alone may no longer be fast enough to protect her business (EVAL).\"</em></p>", "question": "What happens if a student''s evaluation answer ''sits on the fence'' without making a decision?", "options": ["It scores zero evaluation marks, whatever the analysis", "It is acceptable as long as both sides are equally detailed", "It only loses the Knowledge and Understanding marks", "It automatically scores half marks"]}'::jsonb, '{"answer": 0, "explain": "The card states clearly that ''sitting on the fence'' equals 0 evaluation marks — a clear, justified decision is required for those marks."}'::jsonb),
('business:1-6-business-growth:tips:3c224355', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate with Data — 9 marks — Use the Numbers — They''re Worth 2 Free Marks", "reading": "<p>The 9-mark question awards <strong>2 separate marks purely for using numerical data</strong>. This is the most commonly missed opportunity on the entire paper.</p>\n    <p><strong>What counts as quantitative application (Shinz Ltd example):</strong></p>\n    <ul>\n      <li>Combined market share: \"40% + 10% = 50% combined market share\"</li>\n      <li>Market value: \"50% of £460,000 = £230,000\"</li>\n      <li>Share change: \"Shinz''s market share rose by 25 percentage points in 3 years\"</li>\n      <li>Customer satisfaction gap: \"Shinz''s satisfaction is 42 percentage points higher than Littlelong''s\"</li>\n      <li>Post-merger ownership: \"The business would have 5 owners\"</li>\n    </ul>\n    <p><strong>The 9-mark structure:</strong></p>\n    <ul>\n      <li><strong>K (1 mark):</strong> Define what a merger is OR use merger terminology (horizontal, vertical, etc.)</li>\n      <li><strong>U (1 mark):</strong> State one advantage or disadvantage</li>\n      <li><strong>APP (2 marks):</strong> Two uses of numerical data from the case study</li>\n      <li><strong>AN (2 marks):</strong> Two business-facing impacts</li>\n      <li><strong>EVAL (3 marks):</strong> Justified contextual decision</li>\n    </ul>\n    <p><strong>⚠️ Examiner Warning (Shinz Q3):</strong> Many high-ability students lost the Knowledge mark by not explicitly defining a merger or using merger terminology. Don''t assume the examiner knows you know the definition — say it in your first sentence!</p>", "question": "In a 9-mark ''Evaluate with Data'' question, how many marks are specifically available just for using numerical data from the case study?", "options": ["5 marks", "1 mark", "0 marks — data use is not separately credited", "2 marks"]}'::jsonb, '{"answer": 3, "explain": "The card states the 9-mark question awards 2 separate marks purely for quantitative/numerical application, calling it ''the most commonly missed opportunity on the entire paper''."}'::jsonb),
('business:1-6-business-growth:tips:1d70f7bd', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tips', 'mcq', 1, '{"readingTitle": "Recommend — 3 marks — Compare the Two Options — Don''t Just Praise One", "reading": "<p>A 3-mark ''Recommend'' question (like Greggs Q4iii) needs a decision AND a <em>comparative</em> justification.</p>\n    <p><strong>The Formula:</strong></p>\n    <ul>\n      <li><strong>Decision (1 mark):</strong> A clear choice — name the specific method you recommend.</li>\n      <li><strong>Non-contextual comparison (1 mark):</strong> Explain why your choice is BETTER THAN the other option (no case study detail needed).</li>\n      <li><strong>Contextual comparison (2 marks):</strong> Explain why your choice is better using specific details from the case study.</li>\n    </ul>\n    <p><strong>Key rule: The justification MUST be comparative.</strong> Simply listing advantages of your chosen option without mentioning the other gets no justification marks. Look for comparator words: <em>whereas, unlike, compared to, better than, although.</em></p>\n    <p><strong>✅ Full-mark Answer (Greggs):</strong><br/>\n    <em>\"Greggs should merge with the flour producer (1) because it allows the business to quality-assure one of the main ingredients it needs for its vegan pastries (CONT), whereas a takeover of a rival would only put more pressure on management capacity and supply of ingredients (+2).\"</em></p>\n    <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n    <em>\"Greggs should take over a competitor because it will increase market share.\"</em> — No comparison, no context. 1 mark maximum.</p>", "question": "What is the key rule for the justification in a 3-mark ''Recommend'' question?", "options": ["The justification only needs to list advantages of the chosen option", "The justification must include a numerical calculation", "The justification must avoid mentioning the case study business", "The justification must compare the choice to the alternative"]}'::jsonb, '{"answer": 3, "explain": "The justification MUST be comparative — simply listing advantages of the chosen option without comparing it to the other option gets no justification marks."}'::jsonb),
('business:1-6-business-growth:fib:3c81082b', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'fib', 'fib', 2, '{"question": "Organic growth is concerned with the _____ growth of a business, for example by increasing _____.", "blankOptions": {"B1": ["internal", "reduce", "products", "Diversification"], "B2": ["sales", "slow", "reduce", "Diversification"]}}'::jsonb, '{"blanks": {"B1": "internal", "B2": "sales"}}'::jsonb),
('business:1-6-business-growth:fib:b79b9169', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'fib', 'fib', 2, '{"question": "A _____ is when two businesses mutually agree to join together, whereas a _____ is when one business buys a controlling interest in another.", "blankOptions": {"B1": ["vertical", "merger", "slow", "market"], "B2": ["profit", "customers", "takeover", "50"]}}'::jsonb, '{"blanks": {"B1": "merger", "B2": "takeover"}}'::jsonb),
('business:1-6-business-growth:fib:5734f7c6', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'fib', 'fib', 2, '{"question": "When a jam manufacturer buys a fruit farm, this is _____ vertical growth because the farm is a _____.", "blankOptions": {"B1": ["backward", "slow", "50", "customers"], "B2": ["supplier", "sales", "stage", "acquiring"]}}'::jsonb, '{"blanks": {"B1": "backward", "B2": "supplier"}}'::jsonb),
('business:1-6-business-growth:fib:2f1515ca', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'fib', 'fib', 1, '{"question": "A business assembling computers merging with the retailer that sells its computers to the public is an example of _____ vertical growth.", "blankOptions": {"B1": ["shares", "vertical", "forward", "horizontal"]}}'::jsonb, '{"blanks": {"B1": "forward"}}'::jsonb),
('business:1-6-business-growth:fib:773800bf', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'fib', 'fib', 2, '{"question": "When two rival supermarkets merge, this is known as _____ growth because they operate at the same _____ of production.", "blankOptions": {"B1": ["Diversification", "horizontal", "shares", "internal"], "B2": ["stage", "sales", "50", "backward"]}}'::jsonb, '{"blanks": {"B1": "horizontal", "B2": "stage"}}'::jsonb),
('business:1-6-business-growth:fib:d0aa3f3a', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'fib', 'fib', 1, '{"question": "_____ is when a business merges with a company in a completely unrelated industry, entering a brand new market.", "blankOptions": {"B1": ["Diversification", "backward", "rival", "horizontal"]}}'::jsonb, '{"blanks": {"B1": "Diversification"}}'::jsonb),
('business:1-6-business-growth:fib:b02ac673', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'fib', 'fib', 2, '{"question": "Market share is calculated by dividing the _____ of the business by the total _____ in the market and multiplying by 100.", "blankOptions": {"B1": ["sales", "internal", "external", "profit"], "B2": ["stage", "sales", "takeover", "forward"]}}'::jsonb, '{"blanks": {"B1": "sales", "B2": "sales"}}'::jsonb),
('business:1-6-business-growth:fib:06320e9e', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'fib', 'fib', 2, '{"question": "A key disadvantage of organic growth is that it is _____, meaning shareholders may prefer the _____ pace of external growth.", "blankOptions": {"B1": ["Diversification", "slow", "horizontal", "sales"], "B2": ["faster", "profit", "horizontal", "products"]}}'::jsonb, '{"blanks": {"B1": "slow", "B2": "faster"}}'::jsonb),
('business:1-6-business-growth:fib:31bbf72c', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'fib', 'fib', 2, '{"question": "One advantage of external growth is that it can _____ competition by removing a _____ from the market.", "blankOptions": {"B1": ["reduce", "supplier", "organic", "stage"], "B2": ["Diversification", "rival", "slow", "internal"]}}'::jsonb, '{"blanks": {"B1": "reduce", "B2": "rival"}}'::jsonb),
('business:1-6-business-growth:fib:208a1060', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'fib', 'fib', 2, '{"question": "Boohoo initially grew organically through _____ media, and later grew externally by _____ brands such as Debenhams.", "blankOptions": {"B1": ["horizontal", "social", "products", "takeover"], "B2": ["services", "customers", "acquiring", "products"]}}'::jsonb, '{"blanks": {"B1": "social", "B2": "acquiring"}}'::jsonb),
('business:1-6-business-growth:fib:e4e831cf', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'fib', 'fib', 2, '{"question": "Apple has grown primarily through _____ growth by researching and developing new _____, rather than buying many other businesses.", "blankOptions": {"B1": ["organic", "external", "shares", "customers"], "B2": ["products", "acquiring", "stage", "services"]}}'::jsonb, '{"blanks": {"B1": "organic", "B2": "products"}}'::jsonb),
('business:1-6-business-growth:fib:f107dffa', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'fib', 'fib', 1, '{"question": "To gain a controlling interest in a takeover, a business must buy more than _____% of the shares in the other business.", "blankOptions": {"B1": ["social", "customers", "50", "acquiring"]}}'::jsonb, '{"blanks": {"B1": "50"}}'::jsonb),
('business:1-6-business-growth:match:f0efc0fd', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Organic growth”?", "options": ["The growth of a business by takeover or merger with another business.", "Where two or more businesses mutually agree to join together to become one business.", "Where a business takes a controlling interest in another business by buying more than 50% of its shares.", "The internal growth of a business, e.g. by increasing sales or developing new products, without joining with another business."]}'::jsonb, '{"answer": 3, "explain": "“Organic growth” means: The internal growth of a business, e.g. by increasing sales or developing new products, without joining with another business."}'::jsonb),
('business:1-6-business-growth:match:0617129b', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “External growth”?", "options": ["Where two or more businesses mutually agree to join together to become one business.", "Where a business takes a controlling interest in another business by buying more than 50% of its shares.", "A merger or takeover where the two businesses are at the same stage of production in the same industry.", "The growth of a business by takeover or merger with another business."]}'::jsonb, '{"answer": 3, "explain": "“External growth” means: The growth of a business by takeover or merger with another business."}'::jsonb),
('business:1-6-business-growth:match:a8383428', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Merger”?", "options": ["Where a business takes a controlling interest in another business by buying more than 50% of its shares.", "A merger or takeover where the two businesses are at the same stage of production in the same industry.", "When a business merges with, or takes over, a business that supplies it with goods or services.", "Where two or more businesses mutually agree to join together to become one business."]}'::jsonb, '{"answer": 3, "explain": "“Merger” means: Where two or more businesses mutually agree to join together to become one business."}'::jsonb),
('business:1-6-business-growth:match:7158b872', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Takeover”?", "options": ["A merger or takeover where the two businesses are at the same stage of production in the same industry.", "When a business merges with, or takes over, a business that supplies it with goods or services.", "Where a business takes a controlling interest in another business by buying more than 50% of its shares.", "When a business merges with, or takes over, a business that it supplies goods or services to."]}'::jsonb, '{"answer": 2, "explain": "“Takeover” means: Where a business takes a controlling interest in another business by buying more than 50% of its shares."}'::jsonb),
('business:1-6-business-growth:match:0aa85c8f', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Horizontal growth”?", "options": ["When a business merges with, or takes over, a business that supplies it with goods or services.", "When a business merges with, or takes over, a business that it supplies goods or services to.", "A merger or takeover where the two businesses are at the same stage of production in the same industry.", "When a business merges with or takes over another business with which it has no connection — a completely new market."]}'::jsonb, '{"answer": 2, "explain": "“Horizontal growth” means: A merger or takeover where the two businesses are at the same stage of production in the same industry."}'::jsonb),
('business:1-6-business-growth:match:1133b2d3', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Backward vertical growth”?", "options": ["When a business merges with, or takes over, a business that it supplies goods or services to.", "When a business merges with, or takes over, a business that supplies it with goods or services.", "When a business merges with or takes over another business with which it has no connection — a completely new market.", "(Sales of the business ÷ Total sales in the market) × 100"]}'::jsonb, '{"answer": 1, "explain": "“Backward vertical growth” means: When a business merges with, or takes over, a business that supplies it with goods or services."}'::jsonb),
('business:1-6-business-growth:match:07a3dd70', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Forward vertical growth”?", "options": ["When a business merges with or takes over another business with which it has no connection — a completely new market.", "(Sales of the business ÷ Total sales in the market) × 100", "The cost advantages a business gains as it grows larger, such as lower unit costs through bulk buying.", "When a business merges with, or takes over, a business that it supplies goods or services to."]}'::jsonb, '{"answer": 3, "explain": "“Forward vertical growth” means: When a business merges with, or takes over, a business that it supplies goods or services to."}'::jsonb),
('business:1-6-business-growth:match:71de0bf0', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Diversification”?", "options": ["When a business merges with or takes over another business with which it has no connection — a completely new market.", "(Sales of the business ÷ Total sales in the market) × 100", "The cost advantages a business gains as it grows larger, such as lower unit costs through bulk buying.", "A business''s sales as a percentage of total sales in its market — shows how dominant it is compared to rivals."]}'::jsonb, '{"answer": 0, "explain": "“Diversification” means: When a business merges with or takes over another business with which it has no connection — a completely new market."}'::jsonb),
('business:1-6-business-growth:match:9d5d80c8', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market share formula”?", "options": ["The cost advantages a business gains as it grows larger, such as lower unit costs through bulk buying.", "A business''s sales as a percentage of total sales in its market — shows how dominant it is compared to rivals.", "(Sales of the business ÷ Total sales in the market) × 100", "Ownership of more than 50% of a company''s shares, giving the buyer the power to make key business decisions."]}'::jsonb, '{"answer": 2, "explain": "“Market share formula” means: (Sales of the business ÷ Total sales in the market) × 100"}'::jsonb),
('business:1-6-business-growth:match:2e6e5c62', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Economies of scale”?", "options": ["The cost advantages a business gains as it grows larger, such as lower unit costs through bulk buying.", "A business''s sales as a percentage of total sales in its market — shows how dominant it is compared to rivals.", "Ownership of more than 50% of a company''s shares, giving the buyer the power to make key business decisions.", "The internal growth of a business, e.g. by increasing sales or developing new products, without joining with another business."]}'::jsonb, '{"answer": 0, "explain": "“Economies of scale” means: The cost advantages a business gains as it grows larger, such as lower unit costs through bulk buying."}'::jsonb),
('business:1-6-business-growth:match:94b3c1b4', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market share”?", "options": ["A business''s sales as a percentage of total sales in its market — shows how dominant it is compared to rivals.", "Ownership of more than 50% of a company''s shares, giving the buyer the power to make key business decisions.", "The internal growth of a business, e.g. by increasing sales or developing new products, without joining with another business.", "The growth of a business by takeover or merger with another business."]}'::jsonb, '{"answer": 0, "explain": "“Market share” means: A business''s sales as a percentage of total sales in its market — shows how dominant it is compared to rivals."}'::jsonb),
('business:1-6-business-growth:match:5d021746', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Controlling interest”?", "options": ["The internal growth of a business, e.g. by increasing sales or developing new products, without joining with another business.", "The growth of a business by takeover or merger with another business.", "Ownership of more than 50% of a company''s shares, giving the buyer the power to make key business decisions.", "Where two or more businesses mutually agree to join together to become one business."]}'::jsonb, '{"answer": 2, "explain": "“Controlling interest” means: Ownership of more than 50% of a company''s shares, giving the buyer the power to make key business decisions."}'::jsonb),
('business:2-1-role-of-marketing:exam:41ba71f0', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'exam', 'mcq', 1, '{"num": "Q1", "question": "One purpose of marketing at a library is to:", "options": ["Advertise for an apprentice librarian", "Encourage more families to use the library", "Provide better training for librarians", "Update the library''s stock of books"], "hint": "Marketing is about customers and increasing use of a product or service — not about staff or stock management.", "starter": "The purpose of marketing is to..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B — Encourage more families to use the library.</strong></p><p>Marketing is about identifying customer needs and increasing the use of a product or service. Options A and C are HR functions. Option D is an operational decision. Only option B relates directly to the marketing role of increasing usage/sales.</p></div>", "modelAnswer": ""}'::jsonb),
('business:2-1-role-of-marketing:exam:5f977cfb', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'exam', 'mcq', 1, '{"num": "Q2", "question": "One role of marketing within a hair salon is:", "options": ["To advertise a vacancy for a trainee hairdresser", "To ensure that each hairdresser has a contract of employment", "To increase the number of hair appointments booked", "To minimise the likelihood of customers getting head lice"], "hint": "Think about what the marketing function is responsible for — customers and sales, not staff or health and safety.", "starter": "A role of marketing is to..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: C — To increase the number of hair appointments booked.</strong></p><p>Increasing appointments is directly linked to increasing sales — a core marketing role. Option A is recruitment (HR). Option B is contracts of employment (HR/legal). Option D is health and safety (operations).</p></div>", "modelAnswer": ""}'::jsonb),
('business:2-1-role-of-marketing:exam:2a5236a6', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'exam', 'mcq', 1, '{"num": "Q3", "question": "Jacqui works as a marketing assistant at her local library. Which of the following would be part of Jacqui''s job role?", "options": ["Advertising a vacancy for a senior librarian", "Arranging induction training for a new library assistant", "Designing a competition to encourage people to read more", "Improving the way the books are displayed"], "hint": "Think about which option directly relates to attracting and engaging customers/users.", "starter": "As a marketing assistant, Jacqui would..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: C — Designing a competition to encourage people to read more.</strong></p><p>This is a marketing activity aimed at engaging users of the library and increasing its use. Options A and B are HR functions. Option D is an operational/visual merchandising function.</p></div>", "modelAnswer": ""}'::jsonb),
('business:2-1-role-of-marketing:exam:cedcb699', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'exam', 'mcq', 1, '{"num": "Q5", "question": "A manufacturer has decided to run a marketing campaign on national television in a month''s time. As a result of this decision, which one of the following actions might also be necessary?", "options": ["Finance should stop monitoring cash flow", "Human resources should employ some temporary production workers", "Operations management should reduce output", "Purchasing should buy smaller quantities of raw materials"], "hint": "A successful TV campaign will increase demand — what does the business need more of to meet that demand?", "starter": "If demand increases due to the campaign..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B — Human resources should employ some temporary production workers.</strong></p><p>A successful national TV campaign will increase demand for the product. To meet this demand, more products need to be manufactured — so HR needs to employ additional temporary production workers. Options C and D (reducing output and buying smaller quantities) contradict the expected increase in demand. Option A is incorrect — finance should continue monitoring cash flow, especially with increased expenditure.</p></div>", "modelAnswer": ""}'::jsonb),
('business:2-1-role-of-marketing:mcq:55da170a', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'mcq', 'mcq', 1, '{"question": "The principal role of marketing is to:", "options": ["Increase profit", "Increase the skills of the workers", "Increase sales", "Increase the number of products made"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: A — increase sales. The principal role of marketing is to increase sales by identifying customer needs, informing customers, and finding ways to sell more products or services. Profit may follow from increased sales, but increasing profit is not the primary role of the marketing function."}'::jsonb),
('business:2-1-role-of-marketing:mcq:9d0bf09a', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'mcq', 'mcq', 1, '{"question": "The way a business informs customers about a new product or service:", "options": ["Is only done at a national level", "Is only done at a local level", "Can vary depending on the size of the business", "Is the same operation for all businesses"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: B — can vary depending on the size of the business. A large company like Kellogg''s can afford nationwide TV advertising, while a small local pizza delivery business might simply put leaflets through nearby letterboxes. The approach depends on the size, budget, and target market of the business."}'::jsonb),
('business:2-1-role-of-marketing:mcq:e8ac0a2b', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'mcq', 'mcq', 1, '{"question": "A business can understand the needs of its customers by:", "options": ["Setting a lower price than competitors", "Conducting market research", "Making the best possible product", "Having special offers such as buy one get one free"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: A — conducting market research. Market research is the collection of data on consumer habits and needs to help decision-making in marketing. Making a good product, lowering price, or running offers may attract customers but do not in themselves help a business understand what customers need."}'::jsonb),
('business:2-1-role-of-marketing:mcq:bdbf294a', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'mcq', 'mcq', 1, '{"question": "Which of the following would NOT usually lead to an increase in sales?", "options": ["A reduction in price", "A reduction in the range of products", "An increase in advertising", "Selling products in different places"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: C — a reduction in the range of products. Reducing the range of products limits choice for customers and is unlikely to increase sales. Increasing advertising (A), reducing price (B), and selling in different places (D) are all recognised ways to increase sales."}'::jsonb),
('business:2-1-role-of-marketing:mcq:41ba71f0', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'mcq', 'mcq', 1, '{"question": "One purpose of marketing at a library is to:", "options": ["Update the library''s stock of books", "Encourage more families to use the library", "Advertise for an apprentice librarian", "Provide better training for librarians"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — encourage more families to use the library. Marketing is about identifying and meeting customer needs and increasing use of the product or service. Advertising for staff (A), training staff (C), and updating stock (D) are operational/HR functions, not marketing functions."}'::jsonb),
('business:2-1-role-of-marketing:mcq:5f977cfb', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'mcq', 'mcq', 1, '{"question": "One role of marketing within a hair salon is:", "options": ["To ensure that each hairdresser has a contract of employment", "To minimise the likelihood of customers getting head lice", "To advertise a vacancy for a trainee hairdresser", "To increase the number of hair appointments booked"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: C — to increase the number of hair appointments booked. This directly relates to the marketing role of increasing sales. Advertising for staff (A) is a recruitment/HR function. Contracts of employment (B) are an HR/legal function. Head lice prevention (D) is an operational/health and safety matter."}'::jsonb),
('business:2-1-role-of-marketing:mcq:2a5236a6', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'mcq', 'mcq', 1, '{"question": "Jacqui works as a marketing assistant at her local library. Which of the following would be part of Jacqui''s job role?", "options": ["Advertising a vacancy for a senior librarian", "Arranging induction training for a new library assistant", "Improving the way the books are displayed", "Designing a competition to encourage people to read more"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: C — designing a competition to encourage people to read more. This is a marketing activity because it aims to increase engagement with the library''s services. Advertising a vacancy (A) and arranging induction (B) are HR functions. Improving book displays (D) is an operational function."}'::jsonb),
('business:2-1-role-of-marketing:mcq:cedcb699', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'mcq', 'mcq', 1, '{"question": "A manufacturer has decided to run a marketing campaign on national television in a month''s time. As a result of this decision, which one of the following actions might also be necessary?", "options": ["Operations management should reduce output", "Human resources should employ some temporary production workers", "Purchasing should buy smaller quantities of raw materials", "Finance should stop monitoring cash flow"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — Human resources should employ some temporary production workers. A successful TV marketing campaign will likely increase demand, meaning more products need to be made. HR will need to employ extra workers to support the increased production. Options C and D (reducing output or buying less) contradict the expected increase in demand."}'::jsonb),
('business:2-1-role-of-marketing:mcq:57984d4e', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'mcq', 'mcq', 1, '{"question": "A primary purpose of the marketing function of a business is:", "options": ["To employ staff", "To increase sales", "To improve employee retention", "To reduce costs"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: C — to increase sales. The primary purpose of the marketing function is to increase sales by identifying customer needs, informing customers, and finding ways to attract and keep customers. Employing staff and improving retention are HR functions. Reducing costs is primarily an operations/finance concern."}'::jsonb),
('business:2-1-role-of-marketing:mcq:6c3b36ec', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'mcq', 'mcq', 1, '{"question": "Which of the following best describes what marketing involves?", "options": ["Finding the needs of consumers and demonstrating how a business fulfils those needs to increase sales", "Employing the best salespeople to sell products", "Only advertising a product on television", "Making the highest quality product possible"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: B. Marketing is defined as finding the needs of consumers and demonstrating how a business fulfils those needs in a way that increases sales. It is much broader than just advertising — it includes market research, understanding customers, informing them, and finding ways to increase sales through product, price, place, and promotion."}'::jsonb),
('business:2-1-role-of-marketing:tf:545d31f7', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tf', 'tf', 1, '{"question": "The role of marketing is to increase the production of products."}'::jsonb, '{"answer": false, "explain": "FALSE. Increasing production is the role of the Operations/Production department. The role of marketing is to identify customer needs, inform customers, and increase SALES — not to increase production levels."}'::jsonb),
('business:2-1-role-of-marketing:tf:f83b0c86', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tf', 'tf', 1, '{"question": "The role of marketing is to give workers a better place to work."}'::jsonb, '{"answer": false, "explain": "FALSE. Improving working conditions for staff is the role of Human Resources (HR), not marketing. Marketing focuses on customers — identifying their needs, informing them about products, and increasing sales."}'::jsonb),
('business:2-1-role-of-marketing:tf:276d9fdf', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tf', 'tf', 1, '{"question": "The role of marketing is to inform customers of new products."}'::jsonb, '{"answer": true, "explain": "TRUE. Informing customers is one of the three main roles of marketing. This is done through advertising — via TV, radio, social media, newspapers, or leaflets — to make customers aware of products and services available."}'::jsonb),
('business:2-1-role-of-marketing:tf:03158d0e', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tf', 'tf', 1, '{"question": "The role of marketing is to make higher quality products."}'::jsonb, '{"answer": false, "explain": "FALSE. Making products is the role of the Operations/Production department. Marketing''s role is to understand what quality level customers want (through market research) and then communicate it — not to physically produce or improve products."}'::jsonb),
('business:2-1-role-of-marketing:tf:f5e2839f', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tf', 'tf', 1, '{"question": "The role of marketing is to increase the sales of products and services."}'::jsonb, '{"answer": true, "explain": "TRUE. Increasing sales is the principal role of marketing. This can be achieved through advertising, introducing new products, reducing prices, selling in new places, or selling by different methods such as online."}'::jsonb),
('business:2-1-role-of-marketing:tf:b232d988', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tf', 'tf', 1, '{"question": "The role of marketing is to undertake market research in order to understand the needs of customers."}'::jsonb, '{"answer": true, "explain": "TRUE. Conducting market research to identify and understand customers is a key role of marketing. Without understanding what customers want, a business risks making costly mistakes — producing products or services that customers do not want."}'::jsonb),
('business:2-1-role-of-marketing:tf:c4da5cd6', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tf', 'tf', 1, '{"question": "Large businesses and small businesses should always use exactly the same marketing methods."}'::jsonb, '{"answer": false, "explain": "FALSE. The way a business informs customers can vary depending on the SIZE of the business. A large business like Kellogg''s can afford nationwide TV campaigns. A small local business may only need to put leaflets through nearby letterboxes. The right method depends on the budget, target market, and scale of the business."}'::jsonb),
('business:2-1-role-of-marketing:tf:cafa1470', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tf', 'tf', 1, '{"question": "Money spent on marketing always brings about the required increase in sales."}'::jsonb, '{"answer": false, "explain": "FALSE. Money spent on marketing does not ALWAYS bring about the required increase in sales. Marketing effectiveness depends on how well it is targeted, the quality of the campaign, competition, and whether the product actually meets customer needs. This is why market research is important before committing to expensive campaigns."}'::jsonb),
('business:2-1-role-of-marketing:tf:e7c80ef8', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tf', 'tf', 1, '{"question": "Marketing works with the Operations department to inform them of anticipated sales so they can plan their production schedule."}'::jsonb, '{"answer": true, "explain": "TRUE. Marketing works with Operations to share sales predictions so the production team can plan how much to produce. If a major campaign is planned, Operations needs advance notice to ensure enough products are available to meet the expected increase in demand."}'::jsonb),
('business:2-1-role-of-marketing:tf:afccc69b', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tf', 'tf', 1, '{"question": "Reducing the range of products available is likely to increase sales for a business."}'::jsonb, '{"answer": false, "explain": "FALSE. A reduction in the range of products is UNLIKELY to increase sales — it limits customer choice. Marketing typically aims to INCREASE the range of products or services to appeal to more customers and boost sales."}'::jsonb),
('business:2-1-role-of-marketing:learn:c19ad530', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'learn', 'mcq', 1, '{"readingTitle": "What is Marketing?", "reading": "<p><strong>Marketing</strong> is concerned with finding the needs of customers and demonstrating how a business fulfils those needs in a way that increases sales. It is vital to the success of any business.</p>\n<p>Marketing is one of four key functional areas of business. It focuses on the <em>customer</em> rather than the producer. Essentially, marketing ensures that the right product or service is available in the right place at the right time for the right price.</p>\n<p>Some large businesses will spend millions of pounds on marketing; other more local businesses may spend a few pounds on a local newspaper advertisement. Both of these examples have the same objective: they want to <strong>increase sales</strong>.</p>\n<p><strong>Market research</strong> is the collection of data on consumer habits to help decision-making in marketing.</p>\n<p><strong>Important distinction:</strong> Marketing is much broader than just advertising. It includes identifying customer needs, recognising different types of customer, informing customers of available products and services, and ensuring customers receive their goods with an appropriate level of satisfaction.</p>", "question": "According to the core definition, marketing is best described as:", "options": ["Advertising a business''s products on TV and social media", "Setting the lowest possible price for products", "Finding needs and showing how the business meets them", "Manufacturing products to a high quality standard"]}'::jsonb, '{"answer": 2, "explain": "Marketing is defined as finding the needs of customers and demonstrating how a business fulfils those needs in a way that increases sales — advertising is only one part of this, not the whole of marketing."}'::jsonb),
('business:2-1-role-of-marketing:learn:99af99d0', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'learn', 'mcq', 1, '{"readingTitle": "Role 1 — Identifying and Understanding Customers", "reading": "<p>A business must be clear on who it is trying to sell its products or services to. This is about understanding the <strong>target market</strong> — who are the customers?</p>\n<ul>\n<li>Is it trying to sell to all ages, both male and female?</li>\n<li>Or just females between 20 and 40 years old?</li>\n<li>Are they local, national, or international customers?</li>\n<li>What income group do they belong to?</li>\n</ul>\n<p>A <strong>market</strong> is a group of people who share characteristics — e.g. age, income, location, gender. Answers to these questions are found through <strong>market research</strong> (see Unit 2.2).</p>\n<p>The business then analyses this information to make sure that it really is providing what the customer wants. Without checking with the customer, mistakes can be made and these mistakes can prove very costly for businesses.</p>\n<p><strong>Factors influencing who marketing is aimed at:</strong></p>\n<ul>\n<li>Young people may be more likely to respond to advertisements on social media</li>\n<li>Different people may require different products — e.g. some older people may like a mobile phone that has large buttons and is easy to use</li>\n<li>Only rich people may be willing to pay high prices for top quality goods</li>\n<li>Location of potential customers — which country or region do they live in and what language do they speak?</li>\n</ul>", "question": "What is meant by a ''market'' in marketing?", "options": ["The department responsible for setting prices", "People sharing characteristics like age or location", "A physical place where products are bought and sold", "The total number of competitors in an industry"]}'::jsonb, '{"answer": 1, "explain": "The card defines a market as a group of people who share characteristics — e.g. age, income, location, gender."}'::jsonb),
('business:2-1-role-of-marketing:learn:b005abcd', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'learn', 'mcq', 1, '{"readingTitle": "Role 2 — Informing Customers", "reading": "<p>Customers need to be informed by the business of the products and services they are selling. There is no real point in researching what customers want, making that product, and then not informing customers through advertising that it is available.</p>\n<p>Informing customers is normally achieved through <strong>advertising</strong> (see Unit 2.4). There are a number of different ways a business might advertise, including:</p>\n<ul>\n<li>Television</li>\n<li>Radio</li>\n<li>Newspapers and magazines</li>\n<li>Billboards</li>\n<li>Social media</li>\n<li>Leaflets through letterboxes</li>\n</ul>\n<p><strong>Scale varies by business size:</strong> Kellogg''s is a very large company with huge resources which can be used to inform customers of a change to their products or a new lower price offer — this advertising will be aimed at customers countrywide. In contrast, a new local pizza delivery business might simply put leaflets through the letterboxes of homes in the nearby estate to tell possible customers of the service they offer. Each business has a different market to inform.</p>\n<p><strong>Finance matters:</strong> How much a business spends on informing customers will depend on how much it can afford and who it needs to inform.</p>", "question": "Why might a large company like Kellogg''s use nationwide TV advertising while a small local pizza business uses leaflets?", "options": ["Only large businesses are legally allowed to advertise on TV", "Small businesses are not permitted to use social media", "Leaflets are always more effective than TV advertising", "The method depends on the size and resources of the business"]}'::jsonb, '{"answer": 3, "explain": "The card explains that scale varies by business size — Kellogg''s has huge resources for nationwide advertising, while a local business might rely on leaflets, since spending depends on what a business can afford and who it needs to inform."}'::jsonb),
('business:2-1-role-of-marketing:learn:6be16616', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'learn', 'mcq', 1, '{"readingTitle": "Role 3 — Increasing Sales", "reading": "<p>Marketing aims to increase sales. This could be achieved by:</p>\n<ul>\n<li><strong>a) Advertising more</strong> — raising awareness of what is on offer</li>\n<li><strong>b) Introducing a new model</strong> — one that will appeal to more customers, for example, higher definition televisions</li>\n<li><strong>c) Increasing the range of products or services</strong> — Cars such as the Ford Fiesta come in many different models</li>\n<li><strong>d) Reducing the price</strong> — sales may increase, but will profits go up? Selling a new car at £1,000 may well increase sales but no profit will be made. A business must make sure that the price it charges is low enough to attract customers but high enough to make a profit</li>\n<li><strong>e) Selling the product in different places</strong> — Should a business sell to a single chain of shops or a range of different shops? Should it sell direct to customers?</li>\n<li><strong>f) Selling by different methods</strong> — Selling online, or offering digital distribution, will help increase sales of products such as books and music</li>\n</ul>\n<p>These six approaches map to the <strong>4Ps of marketing</strong>: Product, Place, Price, Promotion — which are explored in more detail in later units.</p>", "question": "Why must a business be careful when reducing price to increase sales?", "options": ["Reducing price is illegal under consumer law", "Reducing price always increases production costs", "A lower price may increase sales but shrink profit", "Customers always prefer higher prices"]}'::jsonb, '{"answer": 2, "explain": "The card warns that selling a new car at £1,000 may increase sales but no profit will be made — price must be low enough to attract customers but high enough to make a profit."}'::jsonb),
('business:2-1-role-of-marketing:learn:621d3bcd', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'learn', 'mcq', 1, '{"readingTitle": "Marketing and Other Business Functions", "reading": "<p>Marketing does not operate in isolation — it works closely with other functional areas of the business:</p>\n<div class=\"two-col\" style=\"margin-top:8px;\">\n<div>\n<div class=\"col-head\">Department</div>\n<div class=\"pro-item\"><strong>Human Resources (HR):</strong> Marketing works with HR to check there will be enough workers to support the anticipated level of sales</div>\n<div class=\"pro-item\"><strong>Operations / Production:</strong> Marketing informs Operations of anticipated sales predictions to allow them to plan the production schedule</div>\n</div>\n<div>\n<div class=\"col-head\">Department</div>\n<div class=\"pro-item\"><strong>Finance:</strong> Marketing works with Finance to check there is enough money to pay for the resources required — e.g. an advertising campaign</div>\n<div class=\"pro-item\"><strong>Research &amp; Development:</strong> Marketing works with R&amp;D to develop products that meet the wants and needs of customers</div>\n</div>\n</div>\n<p style=\"margin-top:10px;\"><strong>Example:</strong> A manufacturer decides to run a marketing campaign on national television. As a result, Operations may need to increase output and HR may need to employ some temporary production workers to meet the expected increase in demand.</p>\n<p><strong>Finance available</strong> also directly influences marketing: how much finance is available to spend on research and development of a new product, or on an advertising campaign?</p>", "question": "Which department does marketing work with to ensure there is enough money to fund an advertising campaign?", "options": ["Research & Development", "Finance", "Human Resources", "Operations"]}'::jsonb, '{"answer": 1, "explain": "The card explains that marketing works with Finance to check there is enough money to pay for resources such as an advertising campaign."}'::jsonb),
('business:2-1-role-of-marketing:learn:6418ba5d', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'learn', 'mcq', 1, '{"readingTitle": "Evaluation — Is Marketing Always Worth It?", "reading": "<p>Not all businesses will spend money, time and effort on marketing themselves. Whether a business invests in marketing will often depend on the <strong>size and circumstances of the business</strong>.</p>\n<p><strong>Arguments for marketing spending:</strong></p>\n<ul>\n<li>Informs customers of products and services that are available</li>\n<li>Can significantly increase sales and revenue</li>\n<li>Builds brand awareness and customer loyalty</li>\n<li>Helps identify gaps in the market and understand customer needs</li>\n<li>Essential in competitive markets to stay ahead of rivals</li>\n</ul>\n<p><strong>Arguments against / limitations:</strong></p>\n<ul>\n<li>Money spent on marketing does not always bring about the required increase in sales</li>\n<li>Marketing campaigns can be very expensive — particularly TV advertising</li>\n<li>Small or local businesses may not need extensive marketing — word of mouth may be sufficient</li>\n<li>Poor marketing can waste resources if it targets the wrong customers</li>\n</ul>\n<p><strong>Case study — Kellogg''s:</strong> Throughout its long history, Kellogg''s has moved with the times in the way it markets itself. Its marketing takes many different forms: how it advertises, the different products it introduces (e.g. reducing salt in Corn Flakes by 30%, adding vitamin D to children''s cereals, changing packet designs in 2019), and how the image of the business is portrayed. All this aims to give the customer a positive feel about Kellogg''s which it hopes will lead to customers buying its products.</p>", "question": "Which of these is given as a limitation of spending money on marketing?", "options": ["Marketing is illegal for small businesses", "Marketing has no effect on brand awareness", "Marketing always guarantees a rise in sales", "Marketing spending does not always raise sales"]}'::jsonb, '{"answer": 3, "explain": "The evaluation card notes that money spent on marketing does not always bring about the required increase in sales, and small/local businesses may not need extensive marketing as word of mouth may suffice."}'::jsonb),
('business:2-1-role-of-marketing:misc:53e52082', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students often think marketing is the same as advertising.</p><p><strong>✅ The correct idea:</strong> Marketing is much broader than advertising. It includes: identifying who the customers are (target market), understanding their needs through market research, informing them about products and services, and finding ways to increase sales through product, price, place and promotion. Advertising is just one part of the ''informing customers'' role.</p>", "question": "Which statement most accurately describes the scope of marketing?", "options": ["Marketing is broader than just advertising alone", "Marketing only involves TV and social media campaigns", "Marketing is solely about designing packaging", "Marketing is identical to advertising"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the common misconception that marketing equals advertising — advertising is just one part of the ''informing customers'' role within the broader marketing function."}'::jsonb),
('business:2-1-role-of-marketing:misc:8f5741a5', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students often write that the purpose of marketing is ''to make a profit'' or ''to increase profit''.</p><p><strong>✅ The correct idea:</strong> The principal role of marketing is to INCREASE SALES, not profit directly. The examiner mark scheme specifically states that ''increase sales'' is the correct answer. Profit may result from higher sales, but profit is not the primary purpose of the marketing function — and reducing the price to increase sales could even reduce profit.</p>", "question": "According to the exam mark scheme, what is the principal role of marketing?", "options": ["To reduce costs", "To increase production", "To increase sales", "To increase profit"]}'::jsonb, '{"answer": 2, "explain": "The mark scheme specifically states ''increase sales'' as correct — profit may result from higher sales, but is not the primary purpose of marketing."}'::jsonb),
('business:2-1-role-of-marketing:misc:f78dba7b', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students often give generic answers to ''explain the purpose of marketing within [named business]'' questions without applying to that business.</p><p><strong>✅ The correct idea:</strong> For 2-mark ''explain'' questions about a named business, you must APPLY your answer. A generic answer (''marketing increases sales'') only scores 1 mark. You must link it to the specific business — e.g. ''Marketing helps Ford Motors identify which car models to develop that meet the needs of different market segments, such as eco-friendly small cars and 7-seater people carriers.'' The application mark requires a reference to cars, models, vehicles, or other details from the case study.</p>", "question": "For a 2-mark ''explain the purpose of marketing within [named business]'' question, what is required for the second mark?", "options": ["Listing as many marketing purposes as possible", "Applying the point to specific details of the business", "Repeating the definition of marketing in different words", "Describing the business''s history"]}'::jsonb, '{"answer": 1, "explain": "A generic answer only scores 1 mark; the application mark requires linking the point to specific details from the named business''s case study."}'::jsonb),
('business:2-1-role-of-marketing:misc:b6a0ef43', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students sometimes write that ''sales'' or ''selling'' alone is a purpose of marketing, without adding ''more/increase/additional''.</p><p><strong>✅ The correct idea:</strong> Simply writing ''sales'' or ''sell'' is too vague and is awarded zero by examiners — this is the role of the sales function rather than the marketing function. You must make clear that marketing is about INCREASING sales or selling MORE. Always add ''more'', ''increase'', ''additional'', or ''extra'' when referring to sales as a purpose of marketing.</p>", "question": "Why would an examiner reject the answer ''marketing is about sales'' when explaining the purpose of marketing?", "options": ["Too vague — sales must be described as increasing", "Because the word ''sales'' is banned from GCSE answers", "Because ''sales'' is spelled incorrectly", "Because sales are the responsibility of Operations, not marketing"]}'::jsonb, '{"answer": 0, "explain": "The card warns that writing ''sales'' or ''sell'' alone is awarded zero marks — students must make clear marketing is about INCREASING sales, adding words like ''more'', ''increase'', or ''additional''."}'::jsonb),
('business:2-1-role-of-marketing:misc:718e40d1', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students often confuse the marketing function with HR, operations, or other functional areas.</p><p><strong>✅ The correct idea:</strong> Marketing focuses on customers and increasing sales. HR deals with recruitment, training, and employment. Operations manages production. Finance manages money and budgets. A common exam error is writing that a marketing role includes ''advertising for staff'' or ''arranging training'' — these are HR functions. The marketing function communicates WITH these departments but does not perform their roles.</p>", "question": "Which of the following would be a marketing role rather than an HR role?", "options": ["Issuing contracts of employment", "Arranging induction training for new employees", "Advertising a vacancy for a new staff member", "Designing a sales competition for a product"]}'::jsonb, '{"answer": 3, "explain": "The card clarifies that marketing focuses on customers and increasing sales, while advertising for staff, training and contracts are HR functions that a common exam error wrongly attributes to marketing."}'::jsonb),
('business:2-1-role-of-marketing:misc:eb454350', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students sometimes think all businesses market themselves in exactly the same way.</p><p><strong>✅ The correct idea:</strong> The way a business informs customers CAN VARY DEPENDING ON THE SIZE OF THE BUSINESS. A large business like Kellogg''s uses nationwide TV advertising and social media. A small local business might use leaflets or a local newspaper. The approach depends on the size, budget, and target market. Money spent on marketing does not always bring about the required increase in sales — so businesses must choose their methods carefully.</p>", "question": "What determines the marketing methods a business chooses to use?", "options": ["The colour scheme of the business logo", "The business''s size, budget and target market", "The age of the business owner", "The number of competitors'' products in stock"]}'::jsonb, '{"answer": 1, "explain": "The card states the way a business informs customers can vary depending on the size of the business, with the approach depending on size, budget and target market."}'::jsonb),
('business:2-1-role-of-marketing:tips:3d091132', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tips', 'mcq', 1, '{"readingTitle": "Explain (2 marks) — Explain the Purpose of Marketing Within [Named Business]", "reading": "<p>Structure: Knowledge (1) + Application to the named business (1)</p>\n<ul>\n<li>State ONE purpose of marketing — e.g. to identify customer needs, to inform customers, to increase sales</li>\n<li>Apply it to the specific business using a detail from the case study</li>\n</ul>\n<p><strong>Example (Ford Motors):</strong> \"One purpose of marketing within Ford Motors is to identify the needs of different customer groups (K). This allows Ford to develop a range of models that differ in size — such as eco-friendly small cars, family cars, sports cars and 7-seater people carriers — to meet the individual needs of different market segments (APP).\"</p>\n<p><strong>Common error:</strong> A generic answer (''marketing increases sales'') only scores 1 mark. The application must reference cars, models, vehicles, or other Ford-specific details.</p>", "question": "What two-part structure earns full marks on a 2-mark ''explain the purpose of marketing within [named business]'' question?", "options": ["Two separate purposes of marketing, unapplied", "An example from any business plus a diagram", "A definition of marketing plus a definition of sales", "Knowledge of a purpose plus its business application"]}'::jsonb, '{"answer": 3, "explain": "The tip states the structure is Knowledge (1) + Application to the named business (1) — a generic answer without business-specific application only scores 1 mark."}'::jsonb),
('business:2-1-role-of-marketing:tips:b6b53a71', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tips', 'mcq', 1, '{"readingTitle": "Analyse (3 marks) — Analyse a Benefit of a Marketing Method", "reading": "<p>Structure: Understanding (1) → Application to the business (1) → Business-facing Analysis (1)</p>\n<ul>\n<li>State ONE benefit of the marketing method (e.g. TV reaches a large audience)</li>\n<li>Apply it to the specific business in the question</li>\n<li>Explain the business impact — e.g. effect on sales, revenue, awareness, competitive position</li>\n</ul>\n<p><strong>Example (Fairy Liquid, TV):</strong> \"TV advertising reaches a large audience (U). Fairy Liquid targets households throughout the UK (APP). By reaching a large target audience, more consumers will be informed about Fairy Liquid and so are more likely to buy the product, increasing sales (AN).\"</p>", "question": "What is the correct three-part structure for a 3-mark ''analyse a benefit of a marketing method'' question?", "options": ["Three separate benefits listed without explanation", "Understanding, application, then business analysis", "A definition, an example, and a conclusion", "Application, application, and a final analysis point"]}'::jsonb, '{"answer": 1, "explain": "The tip specifies the structure as Understanding (1) → Application to the business (1) → Business-facing Analysis (1), as shown in the Fairy Liquid TV advertising example."}'::jsonb),
('business:2-1-role-of-marketing:tips:228d98bb', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tips', 'mcq', 1, '{"readingTitle": "Explain (2 marks) — Explain What is Meant by Target Market", "reading": "<p>Structure: Knowledge (1) + Understanding through example (1)</p>\n<ul>\n<li>Define target market — the group of people a business aims its product at</li>\n<li>Give a relevant example — either from the case study or any business</li>\n</ul>\n<p><strong>Example:</strong> \"A target market is the group of customers to whom a business aims its product or service (K). For Fairy Liquid, the target market is households throughout the UK who need a washing-up liquid (U).\"</p>", "question": "To fully answer ''explain what is meant by target market'' for 2 marks, a student should provide:", "options": ["Two unrelated definitions of marketing terms", "An example only, without any definition", "A list of four different target markets", "A definition of target market plus an example"]}'::jsonb, '{"answer": 3, "explain": "The tip requires Knowledge (1) — defining target market as the group a business aims its product at — plus Understanding through a relevant example (1), as in the Fairy Liquid example."}'::jsonb),
('business:2-1-role-of-marketing:tips:4b21a56a', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tips', 'mcq', 1, '{"readingTitle": "Analyse (6 marks — 2×3) — Analyse Two Factors Which Influence How a Business Markets Its Products", "reading": "<p>For each factor: Understanding (1) + Application to the specific business (1) + Analysis of why it affects marketing (1)</p>\n<p><strong>Common factors to know:</strong></p>\n<ul>\n<li><strong>Finance available:</strong> How much money the business has to spend on advertising or R&amp;D will determine the scale and method of marketing</li>\n<li><strong>Who the marketing is aimed at:</strong> Young people respond better to social media; older people may prefer TV or newspapers; rich customers may expect premium advertising</li>\n<li><strong>Location of customers:</strong> Local business = local methods; global business = national/international campaigns</li>\n<li><strong>Competition:</strong> Intense competition means a business must keep its product in customers'' minds</li>\n<li><strong>Size of business:</strong> Small businesses have smaller budgets and target local audiences; large businesses can afford mass-market campaigns</li>\n</ul>\n<p><strong>Apply each factor to the named business using case study details for full marks.</strong></p>", "question": "For the 6-mark ''analyse two factors influencing how a business markets its products'' question, how are the marks awarded?", "options": ["Six marks for simply naming six different factors", "Three marks per factor, covering U, APP and AN", "One mark per factor regardless of detail", "All six marks for a single, fully detailed factor"]}'::jsonb, '{"answer": 1, "explain": "For each of the two factors, marks are awarded for Understanding (1) + Application to the specific business (1) + Analysis of why it affects marketing (1), giving 3 marks per factor."}'::jsonb),
('business:2-1-role-of-marketing:tips:48a25394', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'tips', 'mcq', 1, '{"readingTitle": "Roles of Marketing — Quick Reference — The Three Roles — What Counts as Each?", "reading": "<p><strong>1. Identifying and understanding customers:</strong> Market research, analysing who the target market is (age, gender, income, location), identifying a gap in the market, understanding customer preferences.</p>\n<p><strong>2. Informing customers:</strong> TV, radio, social media, newspapers, billboards, leaflets, websites. The method chosen depends on the target market and budget available.</p>\n<p><strong>3. Increasing sales:</strong> Advertising, new products, wider product range, price reductions, selling in new places (distribution), selling by different methods (online, digital).</p>\n<p><strong>What marketing is NOT:</strong> Recruiting staff (HR), managing production (Operations), managing finances (Finance), training workers (HR). These departments work WITH marketing but marketing does not perform these roles.</p>", "question": "According to the quick reference, which of these is explicitly NOT part of the marketing function?", "options": ["Recruiting and training staff", "Increasing sales through price changes", "Informing customers via TV or social media", "Identifying the target market through research"]}'::jsonb, '{"answer": 0, "explain": "The card states recruiting staff (HR), managing production (Operations), managing finances (Finance) and training workers (HR) are NOT part of marketing, even though these departments work with marketing."}'::jsonb),
('business:2-1-role-of-marketing:fib:a74d8399', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'fib', 'fib', 2, '{"question": "Marketing is concerned with finding the _____ of customers and demonstrating how a business fulfils those needs in a way that increases _____.", "blankOptions": {"B1": ["needs", "products", "target", "places"], "B2": ["places", "managers", "reducing", "sales"]}}'::jsonb, '{"blanks": {"B1": "needs", "B2": "sales"}}'::jsonb),
('business:2-1-role-of-marketing:fib:f46a030a', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'fib', 'fib', 3, '{"question": "The three main roles of marketing are: identifying and understanding _____, informing _____, and increasing _____.", "blankOptions": {"B1": ["managers", "customers", "advertising", "reducing"], "B2": ["target", "customers", "profit", "places"], "B3": ["sales", "products", "reducing", "operations"]}}'::jsonb, '{"blanks": {"B1": "customers", "B2": "customers", "B3": "sales"}}'::jsonb),
('business:2-1-role-of-marketing:fib:b26ff485', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'fib', 'fib', 2, '{"question": "A _____ is a group of people who share characteristics such as age, income or location. A business identifies its _____ market through market research.", "blankOptions": {"B1": ["market", "quality", "price", "places"], "B2": ["sales", "reducing", "target", "operations"]}}'::jsonb, '{"blanks": {"B1": "market", "B2": "target"}}'::jsonb),
('business:2-1-role-of-marketing:fib:8486f2bb', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'fib', 'fib', 2, '{"question": "Marketing does not work alone. It works with _____ to check there are enough workers, and with _____ to check there is enough money to fund campaigns.", "blankOptions": {"B1": ["advertising", "managers", "HR", "sales"], "B2": ["Finance", "online", "operations", "needs"]}}'::jsonb, '{"blanks": {"B1": "HR", "B2": "Finance"}}'::jsonb),
('business:2-1-role-of-marketing:fib:cc8c23e3', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'fib', 'fib', 3, '{"question": "Sales can be increased by reducing _____, selling in different _____, increasing advertising, or introducing new _____.", "blankOptions": {"B1": ["quality", "reducing", "Finance", "price"], "B2": ["profit", "workers", "places", "customers"], "B3": ["needs", "advertising", "target", "products"]}}'::jsonb, '{"blanks": {"B1": "price", "B2": "places", "B3": "products"}}'::jsonb),
('business:2-1-role-of-marketing:fib:2ce4e342', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'fib', 'fib', 2, '{"question": "Marketing is not just about _____. It includes understanding customer needs through _____ research, and then informing customers of what is available.", "blankOptions": {"B1": ["advertising", "places", "Finance", "reducing"], "B2": ["managers", "products", "market", "customers"]}}'::jsonb, '{"blanks": {"B1": "advertising", "B2": "market"}}'::jsonb),
('business:2-1-role-of-marketing:match:f837d8e1', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Marketing”?", "options": ["A group of people who share characteristics such as age, income, or location who a business targets with its products or services", "The specific group of customers a business aims its product or service at", "The collection of data on consumer habits and needs to help decision-making in marketing", "Finding the needs of consumers and demonstrating how a business fulfils those needs in a way that increases sales"]}'::jsonb, '{"answer": 3, "explain": "“Marketing” means: Finding the needs of consumers and demonstrating how a business fulfils those needs in a way that increases sales"}'::jsonb),
('business:2-1-role-of-marketing:match:4f65d23d', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market”?", "options": ["The specific group of customers a business aims its product or service at", "A group of people who share characteristics such as age, income, or location who a business targets with its products or services", "The collection of data on consumer habits and needs to help decision-making in marketing", "Making potential customers aware of products or services through advertising — e.g. TV, radio, social media, leaflets"]}'::jsonb, '{"answer": 1, "explain": "“Market” means: A group of people who share characteristics such as age, income, or location who a business targets with its products or services"}'::jsonb),
('business:2-1-role-of-marketing:match:36014961', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Target market”?", "options": ["The specific group of customers a business aims its product or service at", "The collection of data on consumer habits and needs to help decision-making in marketing", "Making potential customers aware of products or services through advertising — e.g. TV, radio, social media, leaflets", "A key aim of marketing — achieved by advertising more, reducing price, selling in new places, introducing new products or selling by different methods"]}'::jsonb, '{"answer": 0, "explain": "“Target market” means: The specific group of customers a business aims its product or service at"}'::jsonb),
('business:2-1-role-of-marketing:match:cd6cb883', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market research”?", "options": ["Making potential customers aware of products or services through advertising — e.g. TV, radio, social media, leaflets", "A key aim of marketing — achieved by advertising more, reducing price, selling in new places, introducing new products or selling by different methods", "The collection of data on consumer habits and needs to help decision-making in marketing", "Product, Price, Place and Promotion — the four key decisions a business makes when marketing a product or service"]}'::jsonb, '{"answer": 2, "explain": "“Market research” means: The collection of data on consumer habits and needs to help decision-making in marketing"}'::jsonb),
('business:2-1-role-of-marketing:match:89a107f6', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Informing customers”?", "options": ["A key aim of marketing — achieved by advertising more, reducing price, selling in new places, introducing new products or selling by different methods", "Product, Price, Place and Promotion — the four key decisions a business makes when marketing a product or service", "The department marketing must work with to check there is enough money to pay for resources such as an advertising campaign", "Making potential customers aware of products or services through advertising — e.g. TV, radio, social media, leaflets"]}'::jsonb, '{"answer": 3, "explain": "“Informing customers” means: Making potential customers aware of products or services through advertising — e.g. TV, radio, social media, leaflets"}'::jsonb),
('business:2-1-role-of-marketing:match:90a0032f', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Increasing sales”?", "options": ["A key aim of marketing — achieved by advertising more, reducing price, selling in new places, introducing new products or selling by different methods", "Product, Price, Place and Promotion — the four key decisions a business makes when marketing a product or service", "The department marketing must work with to check there is enough money to pay for resources such as an advertising campaign", "Finding the needs of consumers and demonstrating how a business fulfils those needs in a way that increases sales"]}'::jsonb, '{"answer": 0, "explain": "“Increasing sales” means: A key aim of marketing — achieved by advertising more, reducing price, selling in new places, introducing new products or selling by different methods"}'::jsonb),
('business:2-1-role-of-marketing:match:245e00d3', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “4Ps of marketing”?", "options": ["The department marketing must work with to check there is enough money to pay for resources such as an advertising campaign", "Finding the needs of consumers and demonstrating how a business fulfils those needs in a way that increases sales", "A group of people who share characteristics such as age, income, or location who a business targets with its products or services", "Product, Price, Place and Promotion — the four key decisions a business makes when marketing a product or service"]}'::jsonb, '{"answer": 3, "explain": "“4Ps of marketing” means: Product, Price, Place and Promotion — the four key decisions a business makes when marketing a product or service"}'::jsonb),
('business:2-1-role-of-marketing:match:2f7744f8', 'business', 'business:2-1-role-of-marketing', '2.1 The Role of Marketing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Finance (link to marketing)”?", "options": ["Finding the needs of consumers and demonstrating how a business fulfils those needs in a way that increases sales", "The department marketing must work with to check there is enough money to pay for resources such as an advertising campaign", "A group of people who share characteristics such as age, income, or location who a business targets with its products or services", "The specific group of customers a business aims its product or service at"]}'::jsonb, '{"answer": 1, "explain": "“Finance (link to marketing)” means: The department marketing must work with to check there is enough money to pay for resources such as an advertising campaign"}'::jsonb),
('business:2-2-market-research:exam:c10bf13b', 'business', 'business:2-2-market-research', '2.2 Market Research', 'exam', 'mcq', 1, '{"num": "Q1", "question": "Which of the following is an example of primary research?", "options": ["Collecting data from the internet", "Collecting data by asking consumers questions in the local shopping centre", "Collecting data published in the local newspapers", "Collecting data from the last census for a particular age group"], "hint": "Primary research means collecting brand new, first-hand data. Which option involves going out and collecting data directly from people?", "starter": "Primary research involves collecting data first-hand, so the answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B — collecting data by asking consumers questions in the local shopping centre.</strong></p><p>This is primary (field) research because data is collected directly from consumers for the first time. Options A, C and D all involve using data already collected by others — these are all forms of secondary (desk) research.</p></div>", "modelAnswer": ""}'::jsonb),
('business:2-2-market-research:exam:8cee6b92', 'business', 'business:2-2-market-research', '2.2 Market Research', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Market research is important to a business because:", "options": ["It helps develop a good working atmosphere in a business", "It provides information to help develop products", "It shows managers how to motivate their staff", "It keeps staff busy"], "hint": "Market research is about customers and products — not staff or working conditions.", "starter": "Market research is important because it helps a business to..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: B — it provides information to help develop products.</strong></p><p>Market research helps businesses understand what customers want and whether there is demand for a product. This information is then used to develop products that meet customer needs. Options A, C and D all relate to HR and management functions, not market research.</p></div>", "modelAnswer": ""}'::jsonb),
('business:2-2-market-research:exam:c09de167', 'business', 'business:2-2-market-research', '2.2 Market Research', 'exam', 'mcq', 1, '{"num": "Q3", "question": "Quantitative research is:", "options": ["Research undertaken asking a wide variety of people", "Research that concentrates on one part of the population", "Research that deals only with facts and numbers", "Research that has been completed by a competitor business"], "hint": "Think about the word ''quantity'' — what does that suggest about the type of data?", "starter": "Quantitative data is data that is based on..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: C — research that deals only with facts and numbers.</strong></p><p>Quantitative data is based on measurable facts — numbers, percentages, frequencies. It is usually easier to analyse than qualitative (opinion-based) data. Option D describes secondary research from a competitor, which is a separate concept.</p></div>", "modelAnswer": ""}'::jsonb),
('business:2-2-market-research:exam:a47d1ef9', 'business', 'business:2-2-market-research', '2.2 Market Research', 'exam', 'mcq', 1, '{"num": "Q4", "question": "A new business wanting a wide range of information about competitors would most likely use:", "options": ["Questionnaires and interviews", "Internal data", "Newspapers and magazines", "Websites"], "hint": "The business wants information about its COMPETITORS. Which source would give the most comprehensive and up-to-date information about other businesses?", "starter": "A business wanting information about competitors would use..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Mark Scheme</h5><p><strong>Correct answer: D — websites.</strong></p><p>Many companies publish information about themselves and their products online, making websites the most comprehensive and accessible source of competitor information. Internal data (B) is data from within the own business. Questionnaires/interviews (A) are primary methods that would not directly reveal competitor information. Newspapers (C) could also be useful but websites provide the widest and most current range of competitor data.</p></div>", "modelAnswer": ""}'::jsonb),
('business:2-2-market-research:mcq:c10bf13b', 'business', 'business:2-2-market-research', '2.2 Market Research', 'mcq', 'mcq', 1, '{"question": "Which of the following is an example of primary research?", "options": ["Collecting data from the internet", "Collecting data by asking consumers questions in the local shopping centre", "Collecting data published in the local newspapers", "Collecting data from the last census for a particular age group"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — collecting data by asking consumers questions in the local shopping centre. This is primary (field) research because the data is collected first-hand directly from consumers. Options A, C and D all use data already collected by others — these are all forms of secondary (desk) research."}'::jsonb),
('business:2-2-market-research:mcq:8cee6b92', 'business', 'business:2-2-market-research', '2.2 Market Research', 'mcq', 'mcq', 1, '{"question": "Market research is important to a business because:", "options": ["It helps develop a good working atmosphere in a business", "It provides information to help develop products", "It shows managers how to motivate their staff", "It keeps staff busy"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — it provides information to help develop products. Market research helps businesses understand what customers want, whether there is demand for a product, and what price customers will pay. Options A, C and D relate to HR and management functions, not market research."}'::jsonb),
('business:2-2-market-research:mcq:c09de167', 'business', 'business:2-2-market-research', '2.2 Market Research', 'mcq', 'mcq', 1, '{"question": "Quantitative research is:", "options": ["Research undertaken asking a wide variety of people", "Research that concentrates on one part of the population", "Research that deals only with facts and numbers", "Research that has been completed by a competitor business"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — research that deals only with facts and numbers. Quantitative data is based on measurable facts — e.g. how many people buy a product, how often people visit a cinema. It is usually easier to analyse than qualitative data. Option D describes secondary research, not quantitative data."}'::jsonb),
('business:2-2-market-research:mcq:a47d1ef9', 'business', 'business:2-2-market-research', '2.2 Market Research', 'mcq', 'mcq', 1, '{"question": "A new business wanting a wide range of information about competitors would most likely use:", "options": ["Questionnaires and interviews", "Internal data", "Newspapers and magazines", "Websites"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D — websites. Many companies now put information about themselves and their products online, making websites a fast and comprehensive source of secondary data about competitors. Newspapers and magazines (C) could also be useful but websites are the most comprehensive and immediately accessible source. Internal data (B) is data from within the own business. Questionnaires/interviews (A) are primary research methods that would not directly reveal competitor information."}'::jsonb),
('business:2-2-market-research:mcq:aae0e85e', 'business', 'business:2-2-market-research', '2.2 Market Research', 'mcq', 'mcq', 1, '{"question": "Which of the following is an example of qualitative market research data?", "options": ["The number of adults who live and work in the local area", "The percentage of the population who eat out once a week", "The preferences of local residents when eating out", "The prices charged by local competitors"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — the preferences of local residents when eating out. Qualitative data is based on opinions and preferences, not just numbers. Options A, B and D are all facts or numbers — these are examples of quantitative data."}'::jsonb),
('business:2-2-market-research:mcq:d37c1457', 'business', 'business:2-2-market-research', '2.2 Market Research', 'mcq', 'mcq', 1, '{"question": "An interview is an example of:", "options": ["A primary market research method", "A recruitment method", "A training method", "An informal communication method"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A — a primary market research method. An interview where customers are asked questions and the interviewer fills in the answers is a primary (field) research method. Although interviews can also be used in recruitment (B), in the context of market research the answer is primary research. This is a common exam mistake — do not confuse market research interviews with job interviews."}'::jsonb)
